using System;
using System.Buffers.Binary;
using System.Numerics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using System.Runtime.Intrinsics;
using System.Runtime.Intrinsics.X86;
using System.Runtime.Intrinsics.Arm;

namespace HuggingFace.Tokenizers.Internal;

/// <summary>
/// Unicode 规范化查找表。
/// 参考 Rust unicode-normalization-alignments 实现，修复了以下问题：
/// 1. DecomposeNfd 递归改为迭代 + 栈缓冲区，消除栈溢出风险
/// 2. ComposeNfc 增加 Canonical Ordering（按 CCC 排序）
/// 3. ComposeNfc 使用正确的阻断规则（last_ccc >= ch_ccc → 阻断）
/// 4. 使用 BinaryPrimitives 安全读取小端序整数
/// 5. 输出缓冲区边界检查
/// </summary>
internal static class NormalizationTables
{
    // ═══════════════════════════════════════════════════════════════════
    // 底层查找表数据（base64 编码，静态只读，单次解码）
    // ═══════════════════════════════════════════════════════════════════

    // CCC 表：每条记录 5 字节 (int32 key + byte ccc)
    private static readonly byte[] s_cccRaw = Convert.FromBase64String("");
    private static ReadOnlySpan<byte> CccRaw => s_cccRaw;

    // NFD 表：每条记录 12 字节 (int32 key + int32 d1 + int32 d2)
    private static readonly byte[] s_nfdRaw = Convert.FromBase64String("");
    private static ReadOnlySpan<byte> NfdRaw => s_nfdRaw;

    // NFKD 索引表：每条记录 12 字节 (int32 key + int32 offset + int32 length)
    private static readonly byte[] s_nfkdIdxRaw = Convert.FromBase64String("");
    private static ReadOnlySpan<byte> NfkdIdxRaw => s_nfkdIdxRaw;

    // NFKD 字符数据
    private static readonly char[] s_nfkdChars = InitNfkdChars();

    // NFC 组合表：每条记录 12 字节 (int32 base + int32 combining + int32 composed)
    private static readonly byte[] s_composeRaw = Convert.FromBase64String("");
    private static ReadOnlySpan<byte> ComposeRaw => s_composeRaw;
    // NFC 组合 O(1) 查找表 (683KB)
    private static readonly int[] s_composeIndex = MemoryMarshal.Cast<byte, int>(Convert.FromBase64String("")).ToArray();
    private static readonly int[] s_composePages = MemoryMarshal.Cast<byte, int>(Convert.FromBase64String("")).ToArray();

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static int FastCompose(int baseCp, int combiningCp)
    {
        if ((uint)baseCp >= 0x10000 || (uint)combiningCp >= 0x10000) return 0;
        int off = s_composeIndex[baseCp];
        if (off < 0) return 0;
        return s_composePages[off + (combiningCp & 0xFF)];
    }


    // ═══════════════════════════════════════════════════════════════════
    // CCC 查询
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// 获取码点的 Canonical Combining Class。
    /// 5 字节记录：[int32 key][byte ccc]，二分查找，O(log n)。
    /// </summary>
    // 二级页表：BMP 范围 O(1) 查找，非 BMP 回退二分查找
    private static readonly byte[][] s_cccPageTable = InitCccPageTable();

    private static byte[][] InitCccPageTable()
    {
        var pt = new byte[256][];
        pt[3] = Convert.FromBase64String("");
        pt[4] = Convert.FromBase64String("");
        pt[5] = Convert.FromBase64String("");
        pt[6] = Convert.FromBase64String("");
        pt[7] = Convert.FromBase64String("");
        pt[8] = Convert.FromBase64String("");
        pt[9] = Convert.FromBase64String("");
        pt[10] = Convert.FromBase64String("");
        pt[11] = Convert.FromBase64String("");
        pt[12] = Convert.FromBase64String("");
        pt[13] = Convert.FromBase64String("");
        pt[14] = Convert.FromBase64String("");
        pt[15] = Convert.FromBase64String("");
        pt[16] = Convert.FromBase64String("");
        pt[19] = Convert.FromBase64String("");
        pt[23] = Convert.FromBase64String("");
        pt[24] = Convert.FromBase64String("");
        pt[25] = Convert.FromBase64String("");
        pt[26] = Convert.FromBase64String("");
        pt[27] = Convert.FromBase64String("");
        pt[28] = Convert.FromBase64String("");
        pt[29] = Convert.FromBase64String("");
        pt[32] = Convert.FromBase64String("");
        pt[44] = Convert.FromBase64String("");
        pt[45] = Convert.FromBase64String("");
        pt[48] = Convert.FromBase64String("");
        pt[166] = Convert.FromBase64String("");
        pt[168] = Convert.FromBase64String("");
        pt[169] = Convert.FromBase64String("");
        pt[170] = Convert.FromBase64String("");
        pt[171] = Convert.FromBase64String("");
        pt[251] = Convert.FromBase64String("");
        pt[254] = Convert.FromBase64String("");
        return pt;
    }

    // CCC ≠ 0 位图（8KB）：BMP 范围内快速判断码点是否为 combining mark
    // 1 bit per codepoint → 8192 bytes for 0x0000..0xFFFF
    private static readonly byte[] s_cccNotZeroBitmap = InitCccNotZeroBitmap();

    // NFC 惰性位图声明在 s_nfdBmpPageTable 之后（依赖 GetNfd）
    // 实际初始化见下方

    // 扁平化 CCC 查找表（64KB）：单次内存访问，消除二级页表间接寻址
    private static readonly byte[] s_cccFlat = InitCccFlat();

    private static byte[] InitCccFlat()
    {
        var flat = new byte[65536];
        for (int page = 0; page < 256; page++)
        {
            var p = s_cccPageTable[page];
            if (p != null)
                Array.Copy(p, 0, flat, page * 256, 256);
        }
        return flat;
    }

    private static byte[] InitCccNotZeroBitmap()
    {
        var bmp = new byte[8192]; // 65536 bits
        for (int i = 0x80; i < 0x10000; i++)
        {
            var page = s_cccPageTable[i >> 8];
            if (page != null && page[i & 0xFF] != 0)
                bmp[i >> 3] |= (byte)(1 << (i & 7));
        }
        return bmp;
    }

    private static byte[] InitNfcInertBitmap()
    {
        // NFC 惰性 = CCC==0 且 NFD 分解是自身（不分解、不组合、不排序）
        // 这些码点在 NFC 规范化中不会发生任何变化
        var bmp = new byte[8192]; // 65536 bits
        for (int i = 0; i < 0x10000; i++)
        {
            // ASCII (0x00-0x7F) 全部是 NFC 惰性
            if (i < 0x80)
            {
                bmp[i >> 3] |= (byte)(1 << (i & 7));
                continue;
            }
            // CCC != 0 → 不是惰性
            var page = s_cccPageTable[i >> 8];
            if (page != null && page[i & 0xFF] != 0) continue;
            // NFD 分解不是自身 → 不是惰性
            var (d1, d2) = GetNfd(i);
            if (d1 != i) continue;
            // 全部通过 → NFC 惰性
            bmp[i >> 3] |= (byte)(1 << (i & 7));
        }
        return bmp;
    }

    /// <summary>
    /// O(n) 快速判断整个字符串是否已经是 NFC 形式。
    /// 使用 8KB 位图，每个码点只需一次位测试。
    /// 返回 true 表示文本不需要任何 NFC 变化，可以跳过整个规范化流程。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static bool IsAllNfcInert(ReadOnlySpan<char> input)
    {
        // SIMD 加速：Vector&lt;ushort&gt; 批量比较
        int i = 0;
        if (Vector.IsHardwareAccelerated)
        {
            int vecCount = Vector<ushort>.Count;
            var threshold = new Vector<ushort>(0xFFFF);
            for (; i + vecCount <= input.Length; i += vecCount)
            {
                var chunk = new Vector<ushort>(MemoryMarshal.Cast<char, ushort>(input.Slice(i, vecCount)));
                // 任何码点 > 0xFFFF (surrogate) 或不在位图中 → 不是全惰性
                if (Vector.GreaterThanAny(chunk, threshold))
                    return false;
                // 逐个检查位图（SIMD 不能直接做位图查找）
                for (int j = 0; j < vecCount; j++)
                {
                    char c = input[i + j];
                    if ((s_nfcInertBitmap[c >> 3] & (1 << (c & 7))) == 0)
                        return false;
                }
            }
        }
        // 标量处理
        for (; i < input.Length; i++)
        {
            char c = input[i];
            if (c > 0x7F && (s_nfcInertBitmap[c >> 3] & (1 << (c & 7))) == 0)
                return false;
        }
        return true;
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static bool HasNonZeroCcc(int cp)
    {
        if (cp < 0x80) return false;
        if (cp < 0x10000) return (s_cccNotZeroBitmap[cp >> 3] & (1 << (cp & 7))) != 0;
        return GetCcc(cp) != 0;
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static byte GetCcc(int cp)
    {
        if ((uint)cp < 0x80) return 0;  // ASCII fast-path
        // BMP O(1) 扁平数组查找（单次内存访问）
        if ((uint)cp < 0x10000)
            return s_cccFlat[cp];
        // Non-BMP fallback: binary search
        var d = CccRaw;
        ref byte baseRef = ref MemoryMarshal.GetReference(d);
        nint lo = 0, hi = d.Length / 5 - 1;
        while (lo <= hi)
        {
            nint m = (lo + hi) >> 1, o = m * 5;
            int k = Unsafe.ReadUnaligned<int>(ref Unsafe.Add(ref baseRef, o));
            if (k == cp) return Unsafe.Add(ref baseRef, o + 4);
            if (k < cp) lo = m + 1; else hi = m - 1;
        }
        return 0;
    }

        // ═══════════════════════════════════════════════════════════════════
    // NFD 查询
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// 查询 NFD 分解映射。
    /// 12 字节记录：[int32 key][int32 d1][int32 d2]。
    /// 返回 (D1, D2)；若 D1 == cp 则无分解；D2 == 0 则仅一个分解。
    /// </summary>
    // BMP 分解位图：快速判断码点是否有 NFD 分解（8KB）
    private static readonly byte[] s_nfdBmpBitmap = Convert.FromBase64String("");

    // NFD BMP 页表：O(1) 查找码点是否有 NFD 分解及分解索引
    // 每页 256 个 int16 索引（-1 = 无分解），指向 NfdRaw 中的记录
    private static readonly short[][] s_nfdBmpPageTable = InitNfdBmpPageTable();

    // NFC 惰性位图（8KB）：BMP 范围内快速判断码点是否不需要 NFC 变化
    // NFC 惰性 = CCC==0 且 NFD 分解是自身（不分解、不组合、不排序）
    // 1 bit per codepoint → 8192 bytes for 0x0000..0xFFFF
    private static readonly byte[] s_nfcInertBitmap = InitNfcInertBitmap();

    // 扁平化 NFD 分解表（2 × 256KB）：直接存储 d1/d2，消除 ReadUnaligned
    // d1Flat[cp] == cp 表示无分解，d2Flat[cp] == 0 表示仅一个分解
    private static readonly int[] s_nfdD1 = InitNfdD1();
    private static readonly int[] s_nfdD2 = InitNfdD2();

    private static int[] InitNfdD1()
    {
        var d1 = new int[65536];
        for (int i = 0; i < 65536; i++) d1[i] = i; // 默认无分解
        var raw = s_nfdRaw;
        for (int i = 0; i < raw.Length; i += 12)
        {
            int key = Unsafe.ReadUnaligned<int>(ref raw[i]);
            if (key < 65536)
                d1[key] = Unsafe.ReadUnaligned<int>(ref raw[i + 4]);
        }
        return d1;
    }

    private static int[] InitNfdD2()
    {
        var d2 = new int[65536]; // 默认 0
        var raw = s_nfdRaw;
        for (int i = 0; i < raw.Length; i += 12)
        {
            int key = Unsafe.ReadUnaligned<int>(ref raw[i]);
            if (key < 65536)
                d2[key] = Unsafe.ReadUnaligned<int>(ref raw[i + 8]);
        }
        return d2;
    }

    private static short[][] InitNfdBmpPageTable()
    {
        var pt = new short[256][];
        pt[0] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[1] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[2] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[3] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[4] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[6] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[9] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[10] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[11] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[12] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[13] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[15] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[16] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[27] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[30] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[31] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[32] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[33] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[34] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[35] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[42] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[48] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[249] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[250] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        pt[251] = MemoryMarshal.Cast<byte, short>(Convert.FromBase64String("")).ToArray();
        return pt;
    }


    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static (int D1, int D2) GetNfd(int cp)
    {
        if ((uint)cp < 0x80) return (cp, 0);  // ASCII fast-path
        // BMP O(1) 页表查找
        if ((uint)cp < 0x10000)
        {
            var page = s_nfdBmpPageTable[cp >> 8];
            if (page != null)
            {
                int idx = page[cp & 0xFF];
                if (idx >= 0)
                {
                    // 从 NfdRaw 读取分解映射（每条 12 字节：key + d1 + d2）
                    var d = NfdRaw;
                    int off = idx * 12;
                    return (Unsafe.ReadUnaligned<int>(ref Unsafe.Add(ref MemoryMarshal.GetReference(d), off + 4)),
                            Unsafe.ReadUnaligned<int>(ref Unsafe.Add(ref MemoryMarshal.GetReference(d), off + 8)));
                }
            }
            return (cp, 0);
        }
        // Non-BMP fallback: binary search
        var d2 = NfdRaw;
        ref byte baseRef = ref MemoryMarshal.GetReference(d2);
        nint lo = 0, hi = d2.Length / 12 - 1;
        while (lo <= hi)
        {
            nint m = (lo + hi) >> 1, o = m * 12;
            int k = Unsafe.ReadUnaligned<int>(ref Unsafe.Add(ref baseRef, o));
            if (k == cp)
                return (Unsafe.ReadUnaligned<int>(ref Unsafe.Add(ref baseRef, o + 4)),
                        Unsafe.ReadUnaligned<int>(ref Unsafe.Add(ref baseRef, o + 8)));
            if (k < cp) lo = m + 1; else hi = m - 1;
        }
        return (cp, 0);
    }

    // ═══════════════════════════════════════════════════════════════════
    // NFKD 查询
    // ═══════════════════════════════════════════════════════════════════

    private static char[] InitNfkdChars()
    {
        var raw = Convert.FromBase64String("");
        var arr = new char[raw.Length / 2];
        Buffer.BlockCopy(raw, 0, arr, 0, raw.Length);
        return arr;
    }

    /// <summary>
    /// 查询 NFKD 分解（兼容分解）。
    /// 返回码点在 s_nfkdChars 中的切片；若为空则无兼容分解。
    /// </summary>
    public static ReadOnlySpan<char> GetNfkd(int cp)
    {
        var d = NfkdIdxRaw; int lo = 0, hi = d.Length / 12 - 1;
        while (lo <= hi)
        {
            int m = (lo + hi) >> 1, o = m * 12;
            int k = BinaryPrimitives.ReadInt32LittleEndian(d.Slice(o, 4));
            if (k == cp)
            {
                int off = BinaryPrimitives.ReadInt32LittleEndian(d.Slice(o + 4, 4));
                int len = BinaryPrimitives.ReadInt32LittleEndian(d.Slice(o + 8, 4));
                return s_nfkdChars.AsSpan(off, len);
            }
            if (k < cp) lo = m + 1; else hi = m - 1;
        }
        return ReadOnlySpan<char>.Empty;
    }

    // ═══════════════════════════════════════════════════════════════════
    // NFC 组合查询
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// 查询 NFC 正向组合。
    /// 12 字节记录：[int32 base][int32 combining][int32 composed]。
    /// 返回组合后的码点，0 表示不可组合。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static int NfcCompose(int b, int c)
    {
        return FastCompose(b, c);
    }

    // ═══════════════════════════════════════════════════════════════════
    // NFD 分解（递归，带深度保护 + 边界检查）
    // ═══════════════════════════════════════════════════════════════════

    private const int MaxDecompDepth = 18;  // Unicode 标准最大分解深度

    /// <summary>
    /// 对码点进行完全 NFD 递归分解，结果写入 output。
    /// 返回写入的码点数。
    /// </summary>
    public static int DecomposeNfd(int cp, Span<int> output)
    {
        return DecomposeNfdRecursive(cp, output, 0);
    }

    private static int DecomposeNfdRecursive(int cp, Span<int> output, int depth)
    {
        // ASCII fast-path + depth/bounds guard
        if ((uint)cp < 0x80 || depth >= MaxDecompDepth || output.IsEmpty)
        {
            if (!output.IsEmpty) output[0] = cp;
            return 1;
        }

        var (d1, d2) = GetNfd(cp);
        if (d1 == cp) { output[0] = cp; return 1; }

        int pos = DecomposeNfdRecursive(d1, output, depth + 1);
        if (d2 != 0 && pos < output.Length)
            pos += DecomposeNfdRecursive(d2, output.Slice(pos), depth + 1);
        return pos;
    }

    // ═══════════════════════════════════════════════════════════════════
    // Canonical Ordering（按 CCC 排序 combining marks）
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// 对 buffer[start..end) 段按 CCC 排序（稳定排序，保持同 CCC 的原始顺序）。
    /// 参考 Rust unicode-normalization decompose.rs 的 sort_pending 逻辑。
    /// </summary>
    public static void SortByCcc(Span<int> buffer)
    {
        if (buffer.Length <= 1) return;

        // 使用位图快速跳过 CCC=0 的码点，缓存 CCC 值避免重复查找
        // 采用类似 Rust unicode-normalization 的 pending-sort 优化：
        // 只在 CCC>0 的段内做插入排序
        nint runStart = 0;
        for (nint i = 1; i < buffer.Length; i++)
        {
            int key = buffer[(int)i];
            byte ccc;
            if (key < 0x80) continue; // ASCII: CCC always 0, reset run
            if (key < 0x10000)
            {
                if ((s_cccNotZeroBitmap[key >> 3] & (1 << (key & 7))) == 0)
                {
                    // CCC=0：flush pending sort run
                    SortRun(buffer, runStart, i);
                    runStart = i;
                    continue;
                }
                ccc = s_cccFlat[key];
            }
            else
            {
                ccc = GetCcc(key);
                if (ccc == 0) { SortRun(buffer, runStart, i); runStart = i; continue; }
            }

            // Insert into the current combining run
            nint j = i - 1;
            while (j >= runStart)
            {
                int prev = buffer[(int)j];
                byte cccJ;
                if (prev < 0x80) break;
                if (prev < 0x10000)
                {
                    if ((s_cccNotZeroBitmap[prev >> 3] & (1 << (prev & 7))) == 0) break;
                    cccJ = s_cccFlat[prev];
                }
                else
                {
                    cccJ = GetCcc(prev);
                    if (cccJ == 0) break;
                }
                if (cccJ <= ccc) break;
                buffer[(int)j + 1] = prev;
                j--;
            }
            buffer[(int)j + 1] = key;
        }
        // Flush final run
        SortRun(buffer, runStart, buffer.Length);
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static void SortRun(Span<int> buffer, nint start, nint end)
    {
        // Insertion sort within a combining run (typically very short)
        for (nint i = start + 1; i < end; i++)
        {
            int key = buffer[(int)i];
            byte ccc = GetCcc(key);
            if (ccc == 0) continue;
            nint j = i - 1;
            while (j >= start)
            {
                byte cccJ = GetCcc(buffer[(int)j]);
                if (cccJ == 0 || cccJ <= ccc) break;
                buffer[(int)j + 1] = buffer[(int)j];
                j--;
            }
            buffer[(int)j + 1] = key;
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    // NFC 组合（完整 Canonical Composition 算法）
    // 参考 Rust unicode-normalization recompose.rs 的 Recompositions 状态机
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// 对已分解（且已排序）的码点序列执行 NFC Canonical Composition。
    /// 结果写入 output，返回写入的码点数。
    ///
    /// 算法参考 Rust unicode-normalization-alignments 的 Recompositions 状态机：
    /// - 遇到 starter 时输出旧 composee 并开始新组合
    /// - 仅当 lastCcc < ccc 时尝试组合（CCC 严格递增才尝试）
    /// - lastCcc >= ccc 时阻断
    /// </summary>
    public static int ComposeNfc(ReadOnlySpan<int> decomposed, Span<int> output)
    {
        if (decomposed.IsEmpty) return 0;

        int outLen = 0;
        int composee = -1;          // 当前正在组合的 starter，-1 = 无
        int composeeOutIdx = -1;    // composee 在 output 中的位置，-1 = 尚未写入
        int lastCcc = 0;           // 上一个 combining mark 的 CCC

        for (int i = 0; i < decomposed.Length; i++)
        {
            int ch = decomposed[i];
            byte ccc = GetCcc(ch);

            if (composee < 0)
            {
                // 尚无 starter，当前字符成为第一个 starter
                composee = ch;
                composeeOutIdx = -1;
                lastCcc = 0;
                continue;
            }

            // 尝试与 composee 组合（仅当 CCC 严格递增时）
            if (ccc > lastCcc)
            {
                int composed = FastCompose(composee, ch);
                if (composed != 0)
                {
                    composee = composed;
                    // 如果 composee 已写入 output，就地更新
                    if (composeeOutIdx >= 0) output[composeeOutIdx] = composee;
                    continue;
                }
                // 组合失败：保留 composee，输出该 mark
                // 先确保 composee 已写入 output
                if (composeeOutIdx < 0)
                {
                    composeeOutIdx = outLen;
                    if (outLen < output.Length) output[outLen++] = composee;
                }
                if (outLen < output.Length) output[outLen++] = ch;
                lastCcc = ccc;
                continue;
            }

            // ccc <= lastCcc：阻断
            if (ccc == 0)
            {
                // 新 starter：输出旧 composee（如果还未输出），当前成为新 composee
                if (composeeOutIdx < 0)
                {
                    if (outLen < output.Length) output[outLen++] = composee;
                }
                composee = ch;
                composeeOutIdx = -1;
                lastCcc = 0;
                continue;
            }

            // combining mark 被阻断，直接输出
            if (outLen < output.Length) output[outLen++] = ch;
        }

        // 输出最后的 composee（如果还未输出）
        if (composee >= 0 && composeeOutIdx < 0 && outLen < output.Length)
            output[outLen++] = composee;

        return outLen;
    }

    /// <summary>
    /// NFC 组合 + 消耗追踪。与 ComposeNfc 相同逻辑，但同时记录每个输出字符消耗的输入码点数。
    /// 用于 NfcWithTransform 消除二次分解。
    /// </summary>
    public static int ComposeNfcWithConsumed(ReadOnlySpan<int> decomposed, Span<int> output, Span<int> consumedMap)
    {
        if (decomposed.IsEmpty) return 0;

        int outLen = 0;
        int composee = -1;
        int composeeOutIdx = -1;
        int lastCcc = 0;
        int composeeConsumed = 0; // 当前 composee 已消耗的输入码点数

        for (int i = 0; i < decomposed.Length; i++)
        {
            int ch = decomposed[i];
            byte ccc = GetCcc(ch);

            if (composee < 0)
            {
                composee = ch;
                composeeOutIdx = -1;
                lastCcc = 0;
                composeeConsumed = 1;
                continue;
            }

            if (ccc > lastCcc)
            {
                int composed = FastCompose(composee, ch);
                if (composed != 0)
                {
                    composee = composed;
                    composeeConsumed++; // 消耗了一个额外的码点
                    if (composeeOutIdx >= 0) output[composeeOutIdx] = composee;
                    continue;
                }
                // 组合失败
                if (composeeOutIdx < 0)
                {
                    composeeOutIdx = outLen;
                    if (outLen < output.Length) { output[outLen] = composee; consumedMap[outLen] = composeeConsumed; outLen++; }
                }
                if (outLen < output.Length) { output[outLen] = ch; consumedMap[outLen] = 1; outLen++; }
                lastCcc = ccc;
                continue;
            }

            // 阻断
            if (ccc == 0)
            {
                if (composeeOutIdx < 0)
                {
                    if (outLen < output.Length) { output[outLen] = composee; consumedMap[outLen] = composeeConsumed; outLen++; }
                }
                composee = ch;
                composeeOutIdx = -1;
                lastCcc = 0;
                composeeConsumed = 1;
                continue;
            }

            if (outLen < output.Length) { output[outLen] = ch; consumedMap[outLen] = 1; outLen++; }
        }

        if (composee >= 0 && composeeOutIdx < 0 && outLen < output.Length)
        {
            output[outLen] = composee;
            consumedMap[outLen] = composeeConsumed;
            outLen++;
        }

        return outLen;
    }

    // ═══════════════════════════════════════════════════════════════════
    // 端到端 NFC 规范化（优化版，含快速路径）
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// 对输入字符串执行完整 NFC 规范化，结果写入 output 码点缓冲区。
    /// 返回写入的码点数。
    ///
    /// 快速路径（避免不必要的分解/排序/组合）：
    /// 1. 纯 ASCII（所有字节 &lt; 0x80）→ 直接复制，零开销
    /// 2. 无 combining marks（所有 CCC == 0）→ 跳过排序和组合
    /// 3. 分解未改变输入 → 跳过排序和组合
    /// </summary>
    public static int NormalizeNfc(ReadOnlySpan<char> input, Span<int> output)
    {
        if (input.IsEmpty) return 0;

        // ── 快速路径 1: 纯 ASCII ──
        // 所有 char < 0x80 → 无分解、无组合、CCC 全为 0
        if (IsAsciiOnly(input))
        {
            int len = Math.Min(input.Length, output.Length);
            for (int i = 0; i < len; i++)
                output[i] = input[i];
            return len;
        }

        // ── 阶段 1: NFD 分解 ──
        int decompLen = 0;
        int runeCount = 0;
        bool hasCombining = false;

        foreach (var rune in input.EnumerateRunes())
        {
            runeCount++;
            int cp = rune.Value;
            int pos = DecomposeNfd(cp, output.Slice(decompLen));
            // 检查分解结果中是否有 combining marks
            if (!hasCombining)
            {
                for (int j = decompLen; j < decompLen + pos; j++)
                {
                    if (GetCcc(output[j]) != 0) { hasCombining = true; break; }
                }
            }
            decompLen += pos;
        }

        // ── 快速路径 2: 分解未改变输入且无 combining marks ──
        if (decompLen == runeCount && !hasCombining)
        {
            // 输入已经是 NFC，直接输出
            // output 已经被 DecomposeNfd 填充（等于原始码点）
            return decompLen;
        }

        // ── 阶段 2: 按 CCC 排序（仅当有 combining marks 时）──
        if (hasCombining)
            SortByCcc(output.Slice(0, decompLen));

        // ── 阶段 3: NFC 组合 ──
        // 原地组合：compose 结果长度 ≤ decompose 长度，可以直接在 output 上操作
        // 但 ComposeNfc 需要读取 decomposed 同时写入 output，不能原地
        // 使用独立的组合缓冲区
        int maxComp = decompLen;
        Span<int> compBuf = maxComp <= 256
            ? stackalloc int[maxComp]
            : new int[maxComp];
        int compLen = ComposeNfc(output.Slice(0, decompLen), compBuf);
        compBuf.Slice(0, compLen).CopyTo(output);
        return compLen;
    }

    /// <summary>
    /// 原地 NFC 组合。输出长度 ≤ 输入长度，直接在 buffer 上操作。
    /// 避免额外缓冲区分配。
    /// </summary>
    private static int ComposeNfcInPlace(Span<int> buffer, int inputLen)
    {
        if (inputLen == 0) return 0;

        int outLen = 0;
        int composee = -1;
        int composeeOutIdx = -1;
        int lastCcc = 0;

        for (int i = 0; i < inputLen; i++)
        {
            int ch = buffer[i];
            byte ccc = GetCcc(ch);

            if (composee < 0)
            {
                composee = ch;
                composeeOutIdx = -1;
                lastCcc = 0;
                continue;
            }

            if (ccc > lastCcc)
            {
                int composed = FastCompose(composee, ch);
                if (composed != 0)
                {
                    composee = composed;
                    if (composeeOutIdx >= 0) buffer[composeeOutIdx] = composee;
                    continue;
                }
                if (composeeOutIdx < 0)
                {
                    composeeOutIdx = outLen;
                    buffer[outLen++] = composee;
                }
                buffer[outLen++] = ch;
                lastCcc = ccc;
                continue;
            }

            if (ccc == 0)
            {
                if (composeeOutIdx < 0)
                    buffer[outLen++] = composee;
                composee = ch;
                composeeOutIdx = -1;
                lastCcc = 0;
                continue;
            }

            buffer[outLen++] = ch;
        }

        if (composee >= 0 && composeeOutIdx < 0 && outLen < inputLen)
            buffer[outLen++] = composee;

        return outLen;
    }

    // ═══════════════════════════════════════════════════════════════════
    // Unsafe + SIMD 加速 NFC 规范化
    // ═══════════════════════════════════════════════════════════════════

    /// <summary>
    /// SIMD 加速 ASCII 检测（Span 版本，给 NormalizeNfc 用）。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static bool IsAsciiOnly(ReadOnlySpan<char> input)
    {
        unsafe
        {
            fixed (char* p = input)
                return IsAsciiOnly(p, input.Length);
        }
    }

    /// <summary>
    /// SIMD 加速 ASCII 检测：Vector256 优先（16 char），回退 Vector128（8 char）。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static unsafe bool IsAsciiOnly(char* src, int len)
    {
        int i = 0;
        if (Vector256.IsHardwareAccelerated)
        {
            var mask = Vector256.Create((ushort)0xFF80);
            for (; i + 16 <= len; i += 16)
            {
                var vec = Vector256.LoadUnsafe(ref *(ushort*)(src + i));
                if ((vec & mask) != Vector256<ushort>.Zero)
                    return false;
            }
        }
        if (Vector128.IsHardwareAccelerated)
        {
            var mask = Vector128.Create((ushort)0xFF80);
            for (; i + 8 <= len; i += 8)
            {
                var vec = Vector128.LoadUnsafe(ref *(ushort*)(src + i));
                if ((vec & mask) != Vector128<ushort>.Zero)
                    return false;
            }
        }
        for (; i < len; i++)
        {
            if ((src[i] & 0xFF80) != 0) return false;
        }
        return true;
    }

    /// <summary>
    /// SIMD 加速 char→char 复制：Vector256 优先（16 char），回退 Vector128。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static unsafe void MemcpyChar(char* dst, char* src, int count)
    {
        int i = 0;
        if (Vector256.IsHardwareAccelerated)
        {
            for (; i + 16 <= count; i += 16)
            {
                var vec = Vector256.LoadUnsafe(ref *(ushort*)(src + i));
                vec.StoreUnsafe(ref *(ushort*)(dst + i));
            }
        }
        if (Vector128.IsHardwareAccelerated)
        {
            for (; i + 8 <= count; i += 8)
            {
                var vec = Vector128.LoadUnsafe(ref *(ushort*)(src + i));
                vec.StoreUnsafe(ref *(ushort*)(dst + i));
            }
        }
        for (; i < count; i++)
            dst[i] = src[i];
    }

    /// <summary>
    /// SIMD 加速非 BMP 检测：Vector128 批量检测 surrogate pair（0xD800..0xDBFF）。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static unsafe bool ContainsNonBmp(char* src, int len)
    {
        int i = 0;
        if (Vector128.IsHardwareAccelerated)
        {
            var mask = Vector128.Create((ushort)0xFC00);
            var target = Vector128.Create((ushort)0xD800);
            for (; i + 8 <= len; i += 8)
            {
                var vec = Vector128.LoadUnsafe(ref *(ushort*)(src + i));
                // 逐元素比较 (c & 0xFC00) == 0xD800
                var cmp = Vector128.Equals(vec & mask, target);
                if (cmp != Vector128<ushort>.Zero) return true;
            }
        }
        for (; i < len; i++)
        {
            if ((src[i] & 0xFC00) == 0xD800) return true;
        }
        return false;
    }

    /// <summary>
    /// 完整 NFC 规范化入口。unsafe 指针操作 + SIMD 加速。
    /// </summary>
    public static unsafe int NormalizeNfcToChars(ReadOnlySpan<char> input, Span<char> output)
    {
        if (input.IsEmpty) return 0;
        int len = Math.Min(input.Length, output.Length);

        fixed (char* pIn = input, pOut = output)
        {
            // ── 快速路径 1: 纯 ASCII → SIMD memcpy ──
            if (IsAsciiOnly(pIn, len))
            {
                MemcpyChar(pOut, pIn, len);
                return len;
            }

            // ── 快速路径 2: 纯 BMP → 单遍状态机 ──
            if (!ContainsNonBmp(pIn, input.Length))
                return NormalizeNfcBmpUnsafe(pIn, input.Length, pOut, output.Length);

            // ── 完整路径: non-BMP → 3-pass ──
            return NormalizeNfc3Pass(input, output);
        }
    }

    /// <summary>
    /// unsafe 单遍 NFC 状态机：全部指针操作，零边界检查。
    /// 优化：FastCompose O(1) 页表 + NFD 位图快速判断无分解字符。
    /// </summary>
    [SkipLocalsInit]
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static unsafe int NormalizeNfcBmpUnsafe(char* src, int srcLen, char* dst, int dstLen)
    {
        char* srcOrig = src;
        char* srcEnd = src + srcLen;
        char* dstEnd = dst + dstLen;

        // 获取数组首元素 ref（配合 Unsafe.Add 消除 bounds check）
        ref int nfdD1Base = ref s_nfdD1[0];
        ref int nfdD2Base = ref s_nfdD2[0];
        ref byte cccBase = ref s_cccFlat[0];

        // 使用临时缓冲区写入（避免 CCC 乱序时污染 output）
        // 优先使用 output buffer（足够大时），避免 heap alloc + memcpy
        int tmpLen = srcLen * 3;  // 最大膨胀
        char* outPtr;
        char* outStart;
        char* outEnd;
        bool usedDstDirectly = false;

        if (dstLen >= tmpLen)
        {
            // output buffer 足够大，直接写入
            outPtr = dst;
            outStart = dst;
            outEnd = dst + dstLen;
            usedDstDirectly = true;
        }
        else
        {
            char* tmpBuf = stackalloc char[Math.Min(tmpLen, 4096)];
            char[]? tmpArr = tmpLen > 4096 ? new char[tmpLen] : null;
            outPtr = tmpArr != null ? (char*)Unsafe.AsPointer(ref tmpArr[0]) : tmpBuf;
            outStart = outPtr;
            outEnd = outStart + tmpLen;
        }

        // ── 单遍 NFC 状态机 ──
        int starter = -1;
        char* starterPtr = null;
        int lastCcc = 0;
        int maxSeenCcc = 0;

        while (src < srcEnd)
        {
            int cp = *src++;

            // 内联 GetNfd（直接页表查找，不经过位图）
            int d1, d2;
            if (cp < 0x80) { d1 = cp; d2 = 0; }
            else
            {
                d1 = Unsafe.Add(ref nfdD1Base, (nint)(uint)cp);
                d2 = Unsafe.Add(ref nfdD2Base, (nint)(uint)cp);
            }

            if (d1 == cp)
            {
                int ccc;
                if (cp < 0x80) ccc = 0;
                else ccc = Unsafe.Add(ref cccBase, (nint)(uint)cp);

                if (ccc == 0)
                {
                    if (starter >= 0 && starterPtr == null && outPtr < outEnd)
                        *outPtr++ = (char)starter;
                    starter = cp; starterPtr = null; lastCcc = 0; maxSeenCcc = 0;
                }
                else
                {
                    if (ccc < maxSeenCcc)
                    {
                        return NormalizeNfc3Pass(new ReadOnlySpan<char>(srcOrig, srcLen),
                            new Span<char>(dst, dstLen));
                    }
                    if (ccc > maxSeenCcc) maxSeenCcc = ccc;

                    if (starter >= 0 && ccc > lastCcc)
                    {
                        int composed = FastCompose(starter, cp);
                        if (composed != 0)
                        {
                            starter = composed;
                            if (starterPtr != null) *starterPtr = (char)starter;
                            continue;
                        }
                        if (starterPtr == null && outPtr < outEnd) *outPtr++ = (char)starter;
                        if (outPtr < outEnd) *outPtr++ = (char)cp;
                        starter = -1; starterPtr = null; lastCcc = 0;
                        continue;
                    }
                    if (starterPtr == null && starter >= 0 && outPtr < outEnd)
                        *outPtr++ = (char)starter;
                    if (outPtr < outEnd) *outPtr++ = (char)cp;
                    starter = -1; starterPtr = null; lastCcc = 0;
                }
                continue;
            }

            // Inline ProcessCodepointUnsafe for d1
            {
                int ccc1 = d1 < 0x80 ? 0 : Unsafe.Add(ref cccBase, (nint)(uint)d1);
                if (starter < 0)
                {
                    starter = d1; starterPtr = null; lastCcc = 0;
                }
                else if (ccc1 != 0 && ccc1 > lastCcc)
                {
                    int comp = FastCompose(starter, d1);
                    if (comp != 0) { starter = comp; if (starterPtr != null) *starterPtr = (char)starter; }
                    else { if (starterPtr == null && outPtr < outEnd) *outPtr++ = (char)starter; if (outPtr < outEnd) *outPtr++ = (char)d1; starter = -1; starterPtr = null; lastCcc = 0; }
                }
                else
                {
                    if (starterPtr == null && starter >= 0 && outPtr < outEnd) *outPtr++ = (char)starter;
                    if (ccc1 == 0) { starter = d1; starterPtr = null; lastCcc = 0; }
                    else if (outPtr < outEnd) { *outPtr++ = (char)d1; starter = -1; starterPtr = null; lastCcc = 0; }
                }
            }
            if (d2 != 0)
            {
                int ccc2 = d2 < 0x80 ? 0 : Unsafe.Add(ref cccBase, (nint)(uint)d2);
                if (starter < 0)
                {
                    starter = d2; starterPtr = null; lastCcc = 0;
                }
                else if (ccc2 != 0 && ccc2 > lastCcc)
                {
                    int comp = FastCompose(starter, d2);
                    if (comp != 0) { starter = comp; if (starterPtr != null) *starterPtr = (char)starter; }
                    else { if (starterPtr == null && outPtr < outEnd) *outPtr++ = (char)starter; if (outPtr < outEnd) *outPtr++ = (char)d2; starter = -1; starterPtr = null; lastCcc = 0; }
                }
                else
                {
                    if (starterPtr == null && starter >= 0 && outPtr < outEnd) *outPtr++ = (char)starter;
                    if (ccc2 == 0) { starter = d2; starterPtr = null; lastCcc = 0; }
                    else if (outPtr < outEnd) { *outPtr++ = (char)d2; starter = -1; starterPtr = null; lastCcc = 0; }
                }
            }
        }

        if (starter >= 0 && starterPtr == null && outPtr < outEnd)
            *outPtr++ = (char)starter;

        // 输出结果
        if (usedDstDirectly)
        {
            return (int)(outPtr - outStart);
        }
        else
        {
            int resultLen = (int)(outPtr - outStart);
            int copyLen = Math.Min(resultLen, dstLen);
            MemcpyChar(dst, outStart, copyLen);
            return copyLen;
        }
    }

    /// <summary>
    /// unsafe 版 ProcessCodepoint：指针操作，内联 NfcCompose。
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    [SkipLocalsInit]
    private static unsafe void ProcessCodepointUnsafe(
        ref char* outPtr, char* dstEnd,
        ref int starter, ref char* starterPtr, ref int lastCcc,
        int cp)
    {
        // 内联 GetCcc — 扁平数组单次访问
        int ccc;
        if (cp < 0x80) ccc = 0;
        else ccc = s_cccFlat[cp];

        if (starter < 0)
        {
            starter = cp; starterPtr = null; lastCcc = 0;
            return;
        }

        if (ccc != 0 && ccc > lastCcc)
        {
            // O(1) 组合查找
            int composed = FastCompose(starter, cp);

            if (composed != 0)
            {
                starter = composed;
                if (starterPtr != null) *starterPtr = (char)starter;
                return;
            }
            if (starterPtr == null && outPtr < dstEnd) *outPtr++ = (char)starter;
            if (outPtr < dstEnd) *outPtr++ = (char)cp;
            starter = -1; starterPtr = null; lastCcc = 0;
            return;
        }

        if (starterPtr == null && outPtr < dstEnd) *outPtr++ = (char)starter;
        if (ccc == 0)
        {
            starter = cp; starterPtr = null; lastCcc = 0;
        }
        else
        {
            if (outPtr < dstEnd) *outPtr++ = (char)cp;
            starter = -1; starterPtr = null; lastCcc = 0;
        }
    }

    /// <summary>
    /// 完整 3-pass NFC（decompose→sort→compose），用于 CCC 乱序文本。
    /// </summary>
    [MethodImpl(MethodImplOptions.NoInlining)]
    [SkipLocalsInit]
    private static unsafe int NormalizeNfc3Pass(ReadOnlySpan<char> input, Span<char> output)
    {
        int maxDecompLen = input.Length * 6;
        int* cpBuf = stackalloc int[Math.Min(maxDecompLen, 1024)];
        int[]? cpBufArr = maxDecompLen > 1024 ? new int[maxDecompLen] : null;
        Span<int> cpBufSpan = cpBufArr != null ? cpBufArr : new Span<int>(cpBuf, maxDecompLen);

        int decompLen = 0;
        foreach (var rune in input.EnumerateRunes())
            decompLen += DecomposeNfd(rune.Value, cpBufSpan.Slice(decompLen));

        SortByCcc(cpBufSpan.Slice(0, decompLen));

        int* compBuf = stackalloc int[Math.Min(decompLen, 1024)];
        int[]? compBufArr = decompLen > 1024 ? new int[decompLen] : null;
        Span<int> compBufSpan = compBufArr != null ? compBufArr : new Span<int>(compBuf, decompLen);
        int compLen = ComposeNfc(cpBufSpan.Slice(0, decompLen), compBufSpan);

        fixed (char* pOut = output)
        {
            char* outPtr = pOut;
            char* outEnd = pOut + output.Length;
            for (int i = 0; i < compLen && outPtr < outEnd; i++)
            {
                int cp = compBufSpan[i];
                if (cp <= 0xFFFF)
                    *outPtr++ = (char)cp;
                else if (outPtr + 2 <= outEnd)
                {
                    *outPtr++ = (char)(0xD7C0 + (cp >> 10));
                    *outPtr++ = (char)(0xDC00 + (cp & 0x3FF));
                }
            }
            return (int)(outPtr - pOut);
        }
    }
}